solution:
fn main() {
    let _arr = [0u8; 512];

    let my_vec: Vec<i32> = vec![];
    if my_vec.is_empty() {
        println!("Vec is empty!");
    }

    let mut a = 10;
    let mut b = 20;
    std::mem::swap(&mut a, &mut b);

    println!("a: {a}, b: {b}");
}
